import { 神將身, 蔽方, 武拳, 舉臂, 叉腰臂 } from './shinsho.js';
export const 因達羅 = (bi) => 神將身(bi, {
    臂(bi, 筆) {
        const { M, L, C, Qk, S, 衣, 細 } = 筆;
        // 蔽帶：頭光環讓杆（環過 x-13.9 於 z≈3.9 一處）
        蔽方(bi, [[-14.9, 1.2], [-12.9, 1.2], [-12.9, 6.6], [-14.9, 6.6]]);
        衣(() => {
            // 杆：拳下短鐏至叉根
            M(-14.35, 15.0);
            L(-14.35, -0.6);
            S();
            M(-13.45, 15.0);
            L(-13.45, -0.6);
            S();
            // 叉根座與橫枝
            M(-14.7, -0.6);
            L(-13.1, -0.6);
            S();
            M(-15.9, -1.6);
            Qk(-13.9, -2.7, -11.9, -1.6);
            S();
            // 中鋒：直葉
            M(-13.9, -2.4);
            C(-14.5, -4.0, -14.4, -6.6, -13.9, -8.8);
            S();
            M(-13.9, -2.4);
            C(-13.3, -4.0, -13.4, -6.6, -13.9, -8.8);
            S();
            // 側鋒二：自橫枝上曲，鋒內傾
            M(-15.8, -2.0);
            C(-16.5, -4.2, -16.1, -6.3, -15.1, -7.7);
            S();
            M(-15.1, -7.7);
            Qk(-14.85, -7.2, -14.9, -6.5);
            S();
            M(-12.0, -2.0);
            C(-11.3, -4.2, -11.7, -6.3, -12.7, -7.7);
            S();
            M(-12.7, -7.7);
            Qk(-12.95, -7.2, -12.9, -6.5);
            S();
            細(() => { M(-13.9, -3.0); L(-13.9, -7.6); S(); });
        });
        // 臂上舉，拳握杆；左叉腰
        const { 拳 } = 舉臂(bi, 筆, -1);
        武拳(bi, 筆, 拳[0], 拳[1]);
        叉腰臂(bi, 筆, 1);
    },
    冠識(bi, 筆) {
        // 巳冠小識：蜿蜒之蛇——一波三折，首有點睛
        const { M, C, S, 細 } = 筆;
        細(() => bi.dim(0.8, () => {
            M(-0.75, 8.95);
            C(-0.1, 9.15, 0.5, 8.75, 0.35, 8.25);
            S();
            M(0.35, 8.25);
            C(0.2, 7.85, -0.4, 7.9, -0.15, 7.5);
            S();
            bi.A(-0.22, 7.38, 0.13);
        }));
    },
});
